import axios from 'axios';

const api = axios.create({
    baseURL: 'htpp://localhost:8080',
    timeout: 30000,
    headers: {
        'Content-Type': 'application/json'
    }
});

api.interceptors.request.use(
    (config) => {
        console.log(`📤 Fazendo requisição: ${config.method?.toUpperCase()} ${config.url}`);
        const token = localStorage.getItem('token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
            console.log('🔑 Token adicionado ao header');
        }
        return config;
    },
    (error) => {
        console.error('❌ Erro na requisição:', error);
        return Promise.reject(error);
    }
);

// Interceptor para logar respostas
api.interceptors.response.use(
    (response) => {
        console.log(`✅ Resposta recebida: ${response.status} ${response.config.url}`);
        return response;
    },
    (error) => {
        console.error('❌ Erro na resposta:', error.response?.status, error.response?.data);
        return Promise.reject(error);
    }
);

// Auth
export const login = async (login, password) => {
    console.log('📝 Tentando login com:', login);
    return api.post('/auth/login', { login, password });
};

export const register = async (login, password) => {
    console.log('📝 Tentando cadastrar usuário:', login);
    rapi.post('/auth/register', { login, password });
};

// Produtos
export const getProdutos = () => api.get('/produtos');
export const getProdutoEstoque = (id) => api.get(`/produtos/${id}/estoque`);
export const cadastrarProduto = (produto) => api.post('/produtos', produto);

// Clientes
export const getClientes = () => api.get('/clientes');
export const cadastrarCliente = (cliente) => api.post('/clientes', cliente);

// Vendas
export const realizarVenda = (produtoId, clienteId, quantidade) => 
    api.post(`/vendas?produtoId=${produtoId}&clienteId=${clienteId}&quantidade=${quantidade}`);
export const getVendasPorProduto = (produtoId) => api.get(`/vendas/produto/${produtoId}`);

export default api;
